// LIBRARY_PUBLISH → Slack message
// Payload has created/modified/deleted arrays for components, styles and
// variables. Each array item looks like { name, key }.
const j = $json;

const count = (arr) => (arr || []).length;
const names = (arr) => (arr || []).map((x) => x.name).filter(Boolean);

// Summarise only the categories that actually changed,
// e.g. "4 components, 1 style, 2 variables updated".
const group = (label, created, modified, deleted) => {
  const total = count(created) + count(modified) + count(deleted);
  if (!total) return null;
  return total + ' ' + label + (total !== 1 ? 's' : '');
};
const summary = [
  group('component', j.created_components, j.modified_components, j.deleted_components),
  group('style', j.created_styles, j.modified_styles, j.deleted_styles),
  group('variable', j.created_variables, j.modified_variables, j.deleted_variables),
].filter(Boolean).join(', ');

// Preview the first few changed item names: "Button, Card (+4 more)".
const changedNames = [].concat(
  names(j.created_components), names(j.modified_components), names(j.deleted_components),
  names(j.created_styles), names(j.modified_styles), names(j.deleted_styles),
  names(j.created_variables), names(j.modified_variables), names(j.deleted_variables),
);
const preview = changedNames.slice(0, 3).join(', ');
const more = changedNames.length > 3 ? ' (+' + (changedNames.length - 3) + ' more)' : '';

const author = (j.triggered_by && j.triggered_by.handle) || 'Unknown';
const when = slackDate(j.timestamp);

// Build the message line by line; skip lines we have no data for.
const lines = ['🎨 *Library published* — *' + j.file_name + '*'];
if (summary) lines.push(summary + ' updated');
if (preview) lines.push('Changed: ' + preview + more);
if (j.description) lines.push('Note: ' + j.description);
lines.push('by ' + author + (when ? ' · ' + when : ''));
lines.push('<https://www.figma.com/file/' + j.file_key + '|Open in Figma>');

return { slackText: lines.join('\n') };

// Absolute, viewer-local timestamp via a Slack date token
// (renders as e.g. "Jun 28, 2026 at 5:24 PM" in each reader's timezone).
function slackDate(iso) {
  if (!iso) return '';
  const epoch = Math.floor(new Date(iso).getTime() / 1000);
  return '<!date^' + epoch + '^{date_short} at {time}|' + iso + '>';
}

// FILE_COMMENT → Slack message
// The same event fires for new comments, replies (parent_id set) and
// resolves (resolved_at set). The comment body is an array of fragments,
// each either { text } or { mention: <userId> }.
const j = $json;

// Map mentioned user ids → handles, using the top-level mentions[] list.
const handleById = {};
for (const u of (j.mentions || [])) {
  if (u && u.id) handleById[u.id] = u.handle;
}

// Rebuild the comment text, swapping mention ids for "@handle".
const body = (j.comment || [])
  .map((frag) => {
    if (frag && frag.text != null) return frag.text;
    if (frag && frag.mention) return '@' + (handleById[frag.mention] || 'someone');
    return '';
  })
  .join('')
  .trim();

const author = (j.triggered_by && j.triggered_by.handle) || 'Someone';
const mentioned = (j.mentions || []).map((u) => u.handle).filter(Boolean);

// Heading depends on the kind of comment event.
let heading = '💬 *New comment*';
if (j.resolved_at) heading = '💬 *Comment resolved*';
else if (j.parent_id) heading = '💬 *New reply*';

const lines = [heading + ' — *' + j.file_name + '*'];
lines.push(author + (mentioned.length ? ' → ' + mentioned.join(', ') : '') + ': "' + body + '"');
lines.push(
  (slackDate(j.timestamp) ? slackDate(j.timestamp) + ' · ' : '') +
  '<https://www.figma.com/file/' + j.file_key + '?comment-id=' + j.comment_id + '|Reply in Figma>'
);

return { slackText: lines.join('\n') };

// Absolute, viewer-local timestamp via a Slack date token.
function slackDate(iso) {
  if (!iso) return '';
  const epoch = Math.floor(new Date(iso).getTime() / 1000);
  return '<!date^' + epoch + '^{date_short} at {time}|' + iso + '>';
}

// FILE_DELETE → Slack message
const j = $json;

const author = (j.triggered_by && j.triggered_by.handle) || 'Someone';
const when = slackDate(j.timestamp);

const lines = ['🗑️ *File deleted* — *' + j.file_name + '*'];
lines.push('by ' + author + (when ? ' · ' + when : ''));
lines.push('Recoverable from Figma trash for 30 days');

return { slackText: lines.join('\n') };

// Absolute, viewer-local timestamp via a Slack date token.
function slackDate(iso) {
  if (!iso) return '';
  const epoch = Math.floor(new Date(iso).getTime() / 1000);
  return '<!date^' + epoch + '^{date_short} at {time}|' + iso + '>';
}
